var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_NULL","text":{"KOREA":"후우…… 이 차인가?","JPN":"ふう……この車か？","ENG":"*Sigh...* Is that the car?","TWN":"呼……是這台車嗎？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_NULL","text":{"KOREA":"이봐요, 아무도 없습니까?","JPN":"すみません、誰かいませんか？","ENG":"Hello? Is anyone there?","TWN":"喂，有人嗎？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"손들고 가만히 있으십시오.","JPN":"両手をあげてじっとしていてください。","ENG":"Stand there and wave your hand.","TWN":"手舉高別動！"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENTLEMAN_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_NULL","text":{"KOREA":"가, 갑자기 뭐요……! 나는……!","JPN":"い、いきなり何だ……！　私は……！","ENG":"H-huh?! What's happening?! I was just─!","TWN":"為…為什麼突然……！我是……！"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENTLEMAN_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"조용히. 잠깐이면 됩니다.","JPN":"静かに。すぐ終わります。","ENG":"Quiet. It'll only take a second.","TWN":"安靜點，只要一下就好。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENTLEMAN_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이유리. 수상한 걸 가지고 있는지 확인해 봐.","JPN":"カスカベ。怪しいものはないか確認しろ。","ENG":"Yuri, see if he's wearing anything suspicious.","TWN":"李悠麗，搜他身，看他有沒有帶什麼可疑物品。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENTLEMAN_EP9HALF_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"YURI_MILITIA_NULL_NULL","text":{"KOREA":"없어, 대장. 휴대폰에 지갑뿐이야.","JPN":"ないよ、隊長。スマホに財布だけ。","ENG":"Nothing, Captain. All he has is his phone and his wallet.","TWN":"沒有，只有手機和錢包。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LEVIA_MILITIA_NULL_NULL","text":{"KOREA":"따라붙은 사람도 없어요~","JPN":"ついてきた人もいないです～","ENG":"No one seems to be following him too!","TWN":"也沒有人跟蹤他～"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"YURI_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEVIA_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"놀라게 해서 미안합니다. 일단은 수배자 신세라.","JPN":"驚かせてすみません。一応は指名手配中の身なので。","ENG":"I apologize for the sudden scare. But we are wanted fugitives now.","TWN":"不好意思，嚇到您，誰叫我們現在是通緝犯。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"민병대입니다. 의뢰인과 직접 얼굴 보고 얘기하는 건 처음이군요.","JPN":"民兵隊です。こうして直接お会いするのは初めてですね。","ENG":"We are the Militia. I believe this is our first time meeting face to face?","TWN":"我們是民兵隊，這還是我們第一次和委託人面對面談話呢。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"그, 그렇죠. 네.","JPN":"そ、そうですね。","ENG":"T-that's right. Yes.","TWN":"喔…喔喔，是。"},"stage":{"bg":"BACKSTREET","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"그 때는 정말 감사했습니다. 여러분 덕분에 딸아이도 편히 눈을 감았을 거예요.","JPN":"その節は本当にありがとうございました。みなさんのおかげで娘も安らかに眠れたのではないかと思います。","ENG":"I'm grateful for what you did. Thanks to you, my daughter can finally rest in peace.","TWN":"那時候真的很謝謝你們，幸虧有你們，我女兒才可以瞑目。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"이 은혜를 어떻게 갚아야 하나 아내랑 한참 얘기했는데……","JPN":"この恩をどうやって返すべきか妻とよく話し合ったのですが……","ENG":"My wife and I have been talking about how we could ever repay you and─","TWN":"我和太太討論很久，該如何報答你們這份恩情……"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"죄송하지만 이야기를 나누기엔 시간이 많이 없습니다. 어디로 가면 됩니까?","JPN":"すみませんが、世間話をしている時間はありません。どこに行けばいいですか？","ENG":"I'm sorry to cut you off, but we don't have much time. Where do we need to go?","TWN":"很抱歉，我們沒太多時間可以談話，現在要怎麼走？"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"아, 그래서 다들 피난민 꼴로 오신 거군요.","JPN":"あ、それでみんな避難民のような格好をしてるんですね。","ENG":"Oh, that's why you're all dressed like this.","TWN":"喔！難怪你們穿得像難民一樣。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GENTLEMAN_EP9HALF_NULL_REAL","text":{"KOREA":"이쪽으로 오시죠. 안내해 드리겠습니다.","JPN":"こちらにどうぞ。案内しますよ。","ENG":"It's this way. I'll lead the way.","TWN":"這邊請，我來帶路。"},"stage":{"bg":"BACKSTREET","slots":{"L":null,"C":{"char_id":"GENTLEMAN_EP9HALF_NULL_REAL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};